-- 1. WAIS-III — Subtestes (2 séries: Verbais + Execução)
INSERT INTO chart_templates (id, name, description, instrument_name, category, data, is_default) VALUES
('b1000001-0000-4000-8000-000000000001', 'Gráfico: WAIS-III — Subtestes', 'Escores ponderados dos 14 subtestes — verbais e de execução com faixas de classificação', 'WAIS-III', 'Inteligência',
'{"chartType":"bar","displayMode":"separated","series":[{"id":"wais-verb","label":"Subtestes Verbais","color":"#0984E3"},{"id":"wais-exec","label":"Subtestes de Execução","color":"#00B894"}],"categories":[{"id":"c0","label":"VC","values":{"wais-verb":0}},{"id":"c1","label":"SM","values":{"wais-verb":0}},{"id":"c2","label":"AR","values":{"wais-verb":0}},{"id":"c3","label":"DG","values":{"wais-verb":0}},{"id":"c4","label":"IN","values":{"wais-verb":0}},{"id":"c5","label":"CO","values":{"wais-verb":0}},{"id":"c6","label":"SNL","values":{"wais-verb":0}},{"id":"c7","label":"CF","values":{"wais-exec":0}},{"id":"c8","label":"CD","values":{"wais-exec":0}},{"id":"c9","label":"CB","values":{"wais-exec":0}},{"id":"c10","label":"RM","values":{"wais-exec":0}},{"id":"c11","label":"AF","values":{"wais-exec":0}},{"id":"c12","label":"PS","values":{"wais-exec":0}}],"referenceLines":[],"referenceRegions":[{"id":"wr1","label":"Média","yMin":8,"yMax":12,"color":"#00B89422","borderColor":"#00B89422"}],"yAxisLabel":"Escore Ponderado","showValues":true,"showLegend":true,"showRegionLegend":true,"defaultDescription":[{"type":"p","children":[{"text":"Gráfico 1. ","bold":true,"italic":true},{"text":"Subtestes que compõem a bateria WAIS-III. "},{"text":"● Vocabulário (VC)","bold":true},{"text":": conceituação e definições de palavras. "},{"text":"● Semelhança (SM)","bold":true},{"text":": raciocínio abstrato com palavras. "},{"text":"● Aritmética (AR)","bold":true},{"text":": resolver problemas matemáticos através do cálculo mental, envolvendo processos atencionais, segurar e manipular informações através da memória operacional. "},{"text":"● Dígitos (DG)","bold":true},{"text":": ouvir e reproduzir sequências de números, envolve processos atencionais e memória operacional. "},{"text":"● Informação (IN)","bold":true},{"text":": responder a perguntas de conhecimentos gerais que envolve memória episódica e de conteúdo escolar. "},{"text":"● Compreensão (CO)","bold":true},{"text":": compreensão de princípios gerais e de situações sociais. "},{"text":"● Sequência de números e letras (SNL)","bold":true},{"text":": ouvir, organizar e verbalizar sequências de números e letras, envolve processos atencionais e funções executivas. "},{"text":"● Completar figuras (CF)","bold":true},{"text":": processos atencionais, coerência central e raciocínio por imagens. "},{"text":"● Código (CD)","bold":true},{"text":": copiar códigos correspondentes a cada estímulo, processos atencionais, velocidade de processamento visual e motor, coordenação olho mão. "},{"text":"● Cubos (CB)","bold":true},{"text":": processamento visual que envolvem habilidades visuoespaciais, visuoconstrutivas e solução de problemas. "},{"text":"● Raciocínio matricial (RM)","bold":true},{"text":": raciocínio fluído por imagens e solução de problemas. "},{"text":"● Arranjo de figuras (AF)","bold":true},{"text":": colocar em ordem lógico sequencial um conjunto de imagens de forma que faça sentido, a contar uma história, atenção, organização do pensamento e linguagem. "},{"text":"● Procurar símbolos (PS)","bold":true},{"text":": procurar estímulos alvos através do rastreio visual, processos atencionais, velocidade de processamento visual e motor."}]}]}'::JSONB,
true);

